        if isinstance(xml_input, str):
            if os.path.isfile(xml_input):
                # File path
                file_size_mb = os.path.getsize(xml_input) / (1024 * 1024)
                if file_size_mb > max_size_mb:
                    result['errors'].append(f'File size ({file_size_mb:.2f} MB) exceeds maximum allowed size ({max_size_mb} MB)')
                    return result
                
                with open(xml_input, 'r', encoding=encoding) as f:
                    xml_content = f.read()
                result['metadata']['source'] = 'file'
                result['metadata']['file_path'] = xml_input
            else:
                # XML string
                xml_content = xml_input
                result['metadata']['source'] = 'string'
        
        elif isinstance(xml_input, bytes):
            xml_content = xml_input.decode(encoding)
            result['metadata']['source'] = 'bytes'
        
        elif isinstance(xml_input, BytesIO):
            xml_content = xml_input.read().decode(encoding)
            xml_input.seek(0)
            result['metadata']['source'] = 'bytesio'
        
        else:
            result['errors'].append(f'Unsupported input type: {type(xml_input)}')
