def _check_well_formedness(xml_content: str) -> bool:
    """Check basic XML well-formedness."""
    try:
        minidom.parseString(xml_content)
        return True
    except Exception:
        return False


def _validate_against_schema(xml_content: str, schema_path: str) -> Dict[str, Any]:
    """Validate XML against XSD schema."""
    validation_result = {
        'valid': True,
        'errors': [],
        'warnings': []
    }
    
    try:
        from lxml import etree
        
        if not os.path.isfile(schema_path):
            validation_result['valid'] = False
            validation_result['errors'].append(f'Schema file not found: {schema_path}')
            return validation_result
        
        with open(schema_path, 'r') as schema_file:
            schema_root = etree.XML(schema_file.read().encode())
            schema = etree.XMLSchema(schema_root)
        
        xml_doc = etree.XML(xml_content.encode())
        
        if not schema.validate(xml_doc):
            validation_result['valid'] = False
            for error in schema.error_log:
                validation_result['errors'].append(f'Schema validation error: {error.message}')
        
    except ImportError:
        validation_result['warnings'].append('lxml not installed, schema validation skipped')
    except Exception as e:
        validation_result['valid'] = False
        validation_result['errors'].append(f'Schema validation error: {str(e)}')
    
    return validation_result


def _perform_additional_checks(root: ET.Element) -> Dict[str, Any]:
    """Perform additional validation checks."""
    checks = {
        'warnings': []
    }
    
    # Check for duplicate IDs
    ids = {}
    for elem in root.iter():
        elem_id = elem.get('id')
        if elem_id:
            if elem_id in ids:
                checks['warnings'].append(f'Duplicate ID found: {elem_id}')
            ids[elem_id] = True
    
    # Check for empty elements
    empty_count = sum(1 for elem in root.iter() if not elem.text and not elem.attrib and len(elem) == 0)
    if empty_count > 0:
        checks['warnings'].append(f'Found {empty_count} empty elements')
    
    return checks


def _get_tree_depth(element: ET.Element, depth: int = 0) -> int:
    """Calculate the maximum depth of the XML tree."""
    if len(element) == 0:
        return depth
    return max(_get_tree_depth(child, depth + 1) for child in element)


def _extract_namespaces(root: ET.Element) -> Dict[str, str]:
    """Extract all namespaces used in the XML document."""
    namespaces = {}
    for elem in root.iter():
        if elem.tag.startswith('{'):
            ns = elem.tag[1:elem.tag.index('}')]
            if ns not in namespaces.values():
                prefix = elem.prefix if hasattr(elem, 'prefix') else 'ns' + str(len(namespaces))
                namespaces[prefix] = ns
    return namespaces


